mapper.update:
UPDATE ISSUE
SET
    STATUS = #{status},
    RESOLVED_DATE = #{resolvedDate},
    UPDATED_AT = #{updatedAt}
WHERE ISSUE_ID = #{issueId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}

mapper.select:
SELECT

FROM ISSUE I
INNER JOIN PROJECT P ON I.PROJECT_ID = P.PROJECT_ID


        AND I.PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND I.STATUS = #{status}


        AND I.PRIORITY = #{priority}


        AND I.ASSIGNEE_ID = #{assigneeId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}


        AND I.DUE_DATE >= #{dueDateFrom}


        AND I.DUE_DATE <= #{dueDateTo}


        AND (
            I.ISSUE_KEY ILIKE CONCAT('%', #{keyword}, '%')
            OR I.TITLE ILIKE CONCAT('%', #{keyword}, '%')
            OR P.PROJECT_CODE ILIKE CONCAT('%', #{keyword}, '%')
        )


ORDER BY I.CREATED_AT DESC
